import{_ as t,o as r,c as o,ac as a}from"./chunks/framework.DnBnwVZk.js";const x=JSON.parse('{"title":"模块化module.exports,exports,require,export/import","description":"","frontmatter":{"date":"2018-11-24T00:00:00.000Z","categories":["JS"],"tags":["JS"],"publish":true},"headers":[],"relativePath":"views/frontend/js/export.md","filePath":"views/frontend/js/export.md","lastUpdated":1775714960000}'),p={name:"views/frontend/js/export.md"};function i(s,e,l,d,n,m){return r(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1543017600000"},[...e[0]||(e[0]=[a('<h1 id="模块化module-exports-exports-require-export-import" tabindex="-1">模块化module.exports,exports,require,export/import <a class="header-anchor" href="#模块化module-exports-exports-require-export-import" aria-label="Permalink to &quot;模块化module.exports,exports,require,export/import&quot;">​</a></h1><ul><li>module.exports/exports：CommonJS标准定义的模块导出方法，仅在Node环境中可用</li><li>export/import：ES6定义的导出导入方法，只有ES6支持</li><li>require：ES6和node都支持的导入方法：使用方法为let a = require(&#39;路径&#39;)</li><li>module.exports属性表示当前模块对外输出的接口，其他文件加载该模块，实际上就是读取module.exports变量</li><li>exports：node在每一个模块头部隐式的定义了一个exports变量，即var exports=module.exports，若导出的为函数，则只能使用module.exports</li></ul><p>备注：export/import 语法现在node原生不支持，浏览器也不支持，实际使用中都是babel插件转化的，所以尽量不要用</p><h2 id="参考" tabindex="-1">参考： <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考：&quot;">​</a></h2><ul><li>阮一峰博客 <a href="http://javascript.ruanyifeng.com/nodejs/module.html#toc0" target="_blank" rel="noreferrer">http://javascript.ruanyifeng.com/nodejs/module.html#toc0</a></li><li>另一篇博客：<a href="https://segmentfault.com/a/1190000010426778" target="_blank" rel="noreferrer">https://segmentfault.com/a/1190000010426778</a></li></ul>',5)])])}const c=t(p,[["render",i]]);export{x as __pageData,c as default};
